import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { api, getAuthToken, isSignupComplete } from "../api";

export default function Home() {
  const navigate = useNavigate();
  const [stats, setStats] = useState({ shops: 0, medicines: 0 });
  const isLoggedIn = Boolean(getAuthToken());

  const categoryTabs = [
    "For You",
    "Pain Relief",
    "Cold & Flu",
    "Vitamins",
    "Diabetes Care",
    "Skin Care",
    "Heart Health",
    "Baby Care",
    "Fitness",
    "Personal Care",
    "Devices",
  ];

  const spotlightDeals = [
    {
      name: "Paracetamol 650",
      offer: "From Rs 49",
      image: "https://picsum.photos/seed/medicine-paracetamol/500/320",
    },
    {
      name: "Vitamin C Tablets",
      offer: "Flat 35% Off",
      image: "https://picsum.photos/seed/medicine-vitamin/500/320",
    },
    {
      name: "Cough Syrup",
      offer: "From Rs 89",
      image: "https://picsum.photos/seed/medicine-cough/500/320",
    },
    {
      name: "Digital Thermometer",
      offer: "Best Picks",
      image: "https://picsum.photos/seed/medicine-thermometer/500/320",
    },
  ];

  const inDemandDeals = [
    {
      name: "BP Monitor",
      offer: "Up to 30% Off",
      image: "https://picsum.photos/seed/medicine-bp/500/320",
    },
    {
      name: "Hand Sanitizer",
      offer: "Combo Savings",
      image: "https://picsum.photos/seed/medicine-sanitizer/500/320",
    },
    {
      name: "Calcium Capsules",
      offer: "From Rs 199",
      image: "https://picsum.photos/seed/medicine-calcium/500/320",
    },
    {
      name: "Nebulizer",
      offer: "Limited Time Deal",
      image: "https://picsum.photos/seed/medicine-nebulizer/500/320",
    },
  ];

  useEffect(() => {
    const loadStats = async () => {
      try {
        const [shopsRes, medicinesRes] = await Promise.all([
          api.get("/shops/"),
          api.get("/medicines/"),
        ]);
        const medicineCount = Array.isArray(medicinesRes.data)
          ? medicinesRes.data.length
          : (medicinesRes.data.count || 0);
        setStats({ shops: shopsRes.data.length, medicines: medicineCount });
      } catch (err) {
        // Keep default stats if backend is unavailable.
      }
    };

    loadStats();
  }, []);

  return (
    <div className="page">
      <div className="market-shell">
        <div className="market-search-row">
          <input
            className="market-search-input"
            placeholder="Search for medicines, brands and wellness products"
            onFocus={() => navigate("/search")}
            readOnly
          />
          <div className="market-top-links">
            <button onClick={() => navigate("/profile")} className="market-link-btn">Profile</button>
            <button onClick={() => navigate("/orders")} className="market-link-btn">Orders</button>
            <button onClick={() => navigate("/cart")} className="market-link-btn">Cart</button>
          </div>
        </div>

        <div className="market-categories" role="tablist" aria-label="Medicine categories">
          {categoryTabs.map((tab, index) => (
            <button
              key={tab}
              className={`market-category-pill ${index === 0 ? "active" : ""}`}
              onClick={() => navigate("/search")}
            >
              {tab}
            </button>
          ))}
        </div>

        {!isLoggedIn && (
          <div className="hero-card">
            <h2>Join Our Medicine Platform</h2>
            <p>Get access to thousands of quality medicines at competitive prices</p>
            <div className="hero-buttons">
              <button onClick={() => navigate(isSignupComplete() ? "/login" : "/signup")} className="btn-hero">Sign In</button>
              <button onClick={() => navigate("/signup")} className="btn-hero btn-primary">Create Account</button>
            </div>
          </div>
        )}

        <section className="market-highlight-banner">
          <div>
            <h2>Brands In Spotlight</h2>
            <p>Top wellness and medicine picks curated for you</p>
          </div>
          <div className="market-banner-stats">
            <span>{stats.shops}+ Stores</span>
            <span>{stats.medicines}+ Products</span>
          </div>
        </section>

        <section className="deal-section">
          <h3>On everybody's list</h3>
          <div className="deal-track">
            {spotlightDeals.map((deal) => (
              <article key={deal.name} className="deal-card" onClick={() => navigate("/search")}>
                <img src={deal.image} alt={deal.name} loading="lazy" />
                <div className="deal-copy">
                  <p>{deal.name}</p>
                  <strong>{deal.offer}</strong>
                </div>
              </article>
            ))}
          </div>
        </section>

        <section className="deal-section">
          <h3>In demand</h3>
          <div className="deal-track">
            {inDemandDeals.map((deal) => (
              <article key={deal.name} className="deal-card" onClick={() => navigate("/search")}>
                <img src={deal.image} alt={deal.name} loading="lazy" />
                <div className="deal-copy">
                  <p>{deal.name}</p>
                  <strong>{deal.offer}</strong>
                </div>
              </article>
            ))}
          </div>
        </section>
      </div>
    </div>
  );
}
